class Solution(object):
    def minimumAddedCoins(self, coins, target):
        coins.sort()
        reach = 0  # can form all values in [1, reach]
        added = 0
        i = 0
        while reach < target:
            if i < len(coins) and coins[i] <= reach + 1:
                reach += coins[i]
                i += 1
            else:
                # Must add coin of value reach+1
                reach += reach + 1
                added += 1
        return added
